INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-sabbath-jubilee-and-justice', 'bible-tea', 's-leviticus', 'Sabbath, Jubilee & Justice', 'sabbath-jubilee-and-justice', 'Every 7 years, debts cancelled. Every 50 years, everything resets. God''s economic policy is wild.', 'stories/sabbath-jubilee-and-justice/cover.webp', 100, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-organizing-the-camp', 'bible-tea', 's-numbers', 'Organizing the Camp', 'organizing-the-camp', 'Two million people in the desert need structure. God arranges every tribe around his presence at the center.', 'stories/organizing-the-camp/cover.webp', 101, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-camp-rules-and-the-cloud', 'bible-tea', 's-numbers', 'Camp Rules & the Cloud', 'camp-rules-and-the-cloud', 'Purity laws, trumpets, and a cloud that tells them when to move and when to stay. God leads in real-time.', 'stories/camp-rules-and-the-cloud/cover.webp', 102, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-complaining-craving-and-chaos', 'bible-tea', 's-numbers', 'Complaining, Craving & Chaos', 'complaining-craving-and-chaos', 'They''re sick of manna and want meat. God sends quail — so much quail it makes them sick. Be careful what you ask for.', 'stories/complaining-craving-and-chaos/cover.webp', 103, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-12-spies-and-a-40-year-detour', 'bible-tea', 's-numbers', '12 Spies & a 40-Year Detour', '12-spies-and-a-40-year-detour', 'They send 12 spies into the promised land. 10 come back terrified, 2 say ''let''s go.'' Fear wins, and it costs them 40 years.', 'stories/12-spies-and-a-40-year-detour/cover.webp', 104, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-rebellion-and-the-earth-opens', 'bible-tea', 's-numbers', 'Rebellion & the Earth Opens Up', 'rebellion-and-the-earth-opens', 'Korah challenges Moses'' authority. The ground literally opens and swallows the rebels. God does not play.', 'stories/rebellion-and-the-earth-opens/cover.webp', 105, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-snakes-water-and-the-long-road', 'bible-tea', 's-numbers', 'Snakes, Water & the Long Road', 'snakes-water-and-the-long-road', 'More complaining, poisonous snakes, a bronze serpent on a pole, and Moses loses his cool at a rock.', 'stories/snakes-water-and-the-long-road/cover.webp', 106, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-a-new-census-a-new-start', 'bible-tea', 's-numbers', 'A New Census, a New Start', 'a-new-census-a-new-start', 'The old generation is gone. A new census counts a new people ready to finally enter the promised land.', 'stories/a-new-census-a-new-start/cover.webp', 107, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-make-your-promises-count', 'bible-tea', 's-numbers', 'Make Your Promises Count', 'make-your-promises-count', 'Laws about vows and offerings. God takes your word seriously — don''t make promises you won''t keep.', 'stories/make-your-promises-count/cover.webp', 108, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-a-talking-donkey-and-a-hired-prophet', 'bible-tea', 's-numbers', 'A Talking Donkey & a Hired Prophet', 'a-talking-donkey-and-a-hired-prophet', 'A prophet gets hired to curse Israel, but his donkey sees an angel and starts talking. You can''t make this up.', 'stories/a-talking-donkey-and-a-hired-prophet/cover.webp', 109, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-when-curses-wont-stick', 'bible-tea', 's-numbers', 'When Curses Won''t Stick', 'when-curses-wont-stick', 'Balaam tries to curse Israel three times. Every time, blessings come out instead. The enemy switches to a dirtier tactic.', 'stories/when-curses-wont-stick/cover.webp', 110, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-battle-against-midian', 'bible-tea', 's-numbers', 'The Battle Against Midian', 'the-battle-against-midian', 'Justice is served on Midian for leading Israel astray. War in the ancient world was brutal and decisive.', 'stories/the-battle-against-midian/cover.webp', 111, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-dont-get-comfortable-too-early', 'bible-tea', 's-numbers', 'Don''t Get Comfortable Too Early', 'dont-get-comfortable-too-early', 'Two tribes want to settle east of the Jordan. Moses almost loses it — you can''t quit before you cross the finish line.', 'stories/dont-get-comfortable-too-early/cover.webp', 112, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-what-kind-of-leaders-god-wants', 'bible-tea', 's-deuteronomy', 'What Kind of Leaders God Wants', 'what-kind-of-leaders-god-wants', 'Kings, priests, prophets — God lays out the job description. Power must be leashed by Scripture and humility.', 'stories/what-kind-of-leaders-god-wants/cover.webp', 113, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-rules-for-war', 'bible-tea', 's-deuteronomy', 'Rules for War', 'rules-for-war', 'Even in battle, there are limits. Protect the vulnerable, spare the fruit trees, offer peace first.', 'stories/rules-for-war/cover.webp', 114, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-law-for-messy-lives', 'bible-tea', 's-deuteronomy', 'Law for Messy Lives', 'law-for-messy-lives', 'Murder, marriage, lost property, stubborn kids — God has something to say about all of it. Holiness gets practical.', 'stories/law-for-messy-lives/cover.webp', 115, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-community-standards', 'bible-tea', 's-deuteronomy', 'Community Standards', 'community-standards', 'Honesty in court, limits on punishment, care for workers. Covenant love looks like a community that protects its weakest.', 'stories/community-standards/cover.webp', 116, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-one-god-one-place', 'bible-tea', 's-deuteronomy', 'One God, One Place of Worship', 'one-god-one-place', 'No shrines on every hill. One name, one altar, one God. Identity starts with who you worship and how.', 'stories/one-god-one-place/cover.webp', 117, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-what-god-really-wants', 'bible-tea', 's-deuteronomy', 'What God Really Wants', 'what-god-really-wants', 'Not just rituals — heart-level loyalty. Love him, walk in his ways, serve with everything you''ve got.', 'stories/what-god-really-wants/cover.webp', 118, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-dont-let-success-ruin-you', 'bible-tea', 's-deuteronomy', 'Don''t Let Success Ruin You', 'dont-let-success-ruin-you', 'When the blessings roll in, don''t forget who gave them. Gratitude is the guardrail against arrogance.', 'stories/dont-let-success-ruin-you/cover.webp', 119, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-remember-where-you-started', 'bible-tea', 's-deuteronomy', 'Remember Where You Started', 'remember-where-you-started', 'You were slaves. You were nobody. Memory is the best armor against pride and the shortest path to gratitude.', 'stories/remember-where-you-started/cover.webp', 120, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cancel-debts-set-people-free', 'bible-tea', 's-deuteronomy', 'Cancel Debts, Set People Free', 'cancel-debts-set-people-free', 'Every 7 years, wipe the slate clean. Generosity isn''t optional — it''s how the community stays whole.', 'stories/cancel-debts-set-people-free/cover.webp', 121, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-ultimate-choice', 'bible-tea', 's-deuteronomy', 'The Ultimate Choice', 'the-ultimate-choice', 'Blessing or curse, life or death. God puts both options on the table and says choose.', 'stories/the-ultimate-choice/cover.webp', 122, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cities-of-refuge', 'bible-tea', 's-deuteronomy', 'Cities of Refuge', 'cities-of-refuge', 'Safe havens for accidental killers. Even ancient justice had nuance — intent matters.', 'stories/cities-of-refuge/cover.webp', 123, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-setting-boundaries', 'bible-tea', 's-deuteronomy', 'Setting Boundaries', 'setting-boundaries', 'Property lines and power plays. God cares about borders, honesty, and keeping your word.', 'stories/setting-boundaries/cover.webp', 124, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fair-play-and-fair-trade', 'bible-tea', 's-deuteronomy', 'Fair Play & Fair Trade', 'fair-play-and-fair-trade', 'Honest scales, fair treatment, no cheating in business or worship. Integrity in the small stuff matters.', 'stories/fair-play-and-fair-trade/cover.webp', 125, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-moses-farewell-address', 'bible-tea', 's-deuteronomy', 'Moses'' Farewell Address', 'moses-farewell-address', 'A song, a blessing over each tribe, one last look from a mountain. The final words of the greatest prophet.', 'stories/moses-farewell-address/cover.webp', 126, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-choose-life-or-death', 'bible-tea', 's-deuteronomy', 'Choose Life or Death', 'choose-life-or-death', 'The choice is near you — in your mouth and in your heart. God begs them to choose life.', 'stories/choose-life-or-death/cover.webp', 127, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-blessings-and-curses', 'bible-tea', 's-deuteronomy', 'Blessings & Curses', 'blessings-and-curses', 'Obey and flourish, disobey and everything falls apart. Moses lays out the two paths with brutal clarity.', 'stories/blessings-and-curses/cover.webp', 128, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-warning-song', 'bible-tea', 's-deuteronomy', 'The Warning Song', 'the-warning-song', 'Moses writes a song predicting exactly how Israel will mess up. It''s a warning disguised as poetry.', 'stories/the-warning-song/cover.webp', 129, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-joshua-takes-command', 'bible-tea', 's-joshua', 'Joshua Takes Command', 'joshua-takes-command', 'New leader, same God. Joshua steps up, sends spies, and a prostitute named Rahab hides them on her roof.', 'stories/joshua-takes-command/cover.webp', 130, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-crossing-the-jordan', 'bible-tea', 's-joshua', 'Crossing the Jordan', 'crossing-the-jordan', 'The priests step into the flooding river and it stops. They walk across on dry ground and stack stones to remember.', 'stories/crossing-the-jordan/cover.webp', 131, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-achans-hidden-sin', 'bible-tea', 's-joshua', 'Achan''s Hidden Sin', 'achans-hidden-sin', 'One man steals forbidden loot and hides it under his tent. Israel loses the next battle because of it.', 'stories/achans-hidden-sin/cover.webp', 132, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-gibeonite-trick', 'bible-tea', 's-joshua', 'The Gibeonite Trick & the Sun Stands Still', 'the-gibeonite-trick', 'A fake peace treaty fools Joshua. Then God stops the sun mid-sky so Israel can win a battle. Wild day.', 'stories/the-gibeonite-trick/cover.webp', 133, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-conquering-the-land', 'bible-tea', 's-joshua', 'Conquering the Land', 'conquering-the-land', 'Campaign after campaign, the map fills in. The promise takes shape one battle at a time.', 'stories/conquering-the-land/cover.webp', 134, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-caleb-claims-his-mountain', 'bible-tea', 's-joshua', 'Caleb Claims His Mountain', 'caleb-claims-his-mountain', '85 years old, still swinging. Caleb says ''give me the hill with the giants on it'' and takes it.', 'stories/caleb-claims-his-mountain/cover.webp', 135, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-claim-your-inheritance', 'bible-tea', 's-joshua', 'Claim Your Inheritance', 'claim-your-inheritance', 'The land is divided but some tribes are lazy about claiming it. Don''t settle for tents when God promised territory.', 'stories/claim-your-inheritance/cover.webp', 136, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-safe-cities-sacred-spaces', 'bible-tea', 's-joshua', 'Safe Cities, Sacred Spaces', 'safe-cities-sacred-spaces', 'Cities of refuge get assigned. Levite towns are scattered across the land. Justice and worship everywhere.', 'stories/safe-cities-sacred-spaces/cover.webp', 137, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-altar-that-almost-started-a-war', 'bible-tea', 's-joshua', 'The Altar That Almost Started a War', 'the-altar-that-almost-started-a-war', 'Two and a half tribes build an altar and the rest of Israel almost goes to civil war over it. Talking it out saves them.', 'stories/the-altar-that-almost-started-a-war/cover.webp', 138, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-joshuas-final-challenge', 'bible-tea', 's-joshua', 'Joshua''s Final Challenge', 'joshuas-final-challenge', '''Choose this day who you will serve.'' Joshua draws a line and dares Israel to commit.', 'stories/joshuas-final-challenge/cover.webp', 139, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-cycle-of-disobedience', 'bible-tea', 's-judges', 'The Cycle of Disobedience', 'the-cycle-of-disobedience', 'Sin, suffering, crying out, rescue, repeat. Israel falls into a pattern that defines an entire era.', 'stories/the-cycle-of-disobedience/cover.webp', 140, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-deborah-and-jael', 'bible-tea', 's-judges', 'Deborah & the Tent Peg', 'deborah-and-jael', 'A female judge leads Israel to battle. Then another woman ends the war with a tent stake. Don''t underestimate them.', 'stories/deborah-and-jael/cover.webp', 141, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-gideon-vs-the-midianites', 'bible-tea', 's-judges', 'Gideon vs. the Midianites', 'gideon-vs-the-midianites', 'God cuts Gideon''s army from 32,000 to 300. Torches, jars, and trumpets vs a massive army. God loves impossible odds.', 'stories/gideon-vs-the-midianites/cover.webp', 142, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-when-victory-goes-to-your-head', 'bible-tea', 's-judges', 'When Victory Goes to Your Head', 'when-victory-goes-to-your-head', 'Gideon wins but makes an idol from the gold. Victory without humility turns sour fast.', 'stories/when-victory-goes-to-your-head/cover.webp', 143, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-bramble-king', 'bible-tea', 's-judges', 'The Bramble King', 'the-bramble-king', 'Abimelech murders 70 brothers to become king. A parable about a bramble bush predicts his downfall. Ego destroys.', 'stories/the-bramble-king/cover.webp', 144, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-jephthahs-reckless-vow', 'bible-tea', 's-judges', 'Jephthah''s Reckless Vow', 'jephthahs-reckless-vow', 'A rough-edged warrior makes a vow he can''t take back. It costs him the thing he loves most.', 'stories/jephthahs-reckless-vow/cover.webp', 145, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-everyone-did-what-they-wanted', 'bible-tea', 's-judges', 'Everyone Did What They Wanted', 'everyone-did-what-they-wanted', 'No king, no rules, pure chaos. Israel hits rock bottom. The horror shows what happens without God.', 'stories/everyone-did-what-they-wanted/cover.webp', 146, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-homemade-religion', 'bible-tea', 's-judges', 'Homemade Religion', 'homemade-religion', 'A guy builds his own shrine, hires his own priest, and a whole tribe steals it. DIY worship leads nowhere good.', 'stories/homemade-religion/cover.webp', 147, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-sauls-last-stand', 'bible-tea', 's-2samuel', 'Saul''s Last Stand', 'sauls-last-stand', 'The first king falls in battle. David mourns his enemy with one of the most beautiful laments ever written.', 'stories/sauls-last-stand/cover.webp', 148, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-two-kings-two-armies', 'bible-tea', 's-2samuel', 'Two Kings, Two Armies', 'two-kings-two-armies', 'Israel splits between David and Saul''s son. Rival generals, risky diplomacy, and a long power struggle.', 'stories/two-kings-two-armies/cover.webp', 149, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-david-dances-before-the-ark', 'bible-tea', 's-2samuel', 'David Dances Before the Ark', 'david-dances-before-the-ark', 'The Ark comes to Jerusalem. David dances with zero shame. His wife watches from the window and judges him hard.', 'stories/david-dances-before-the-ark/cover.webp', 150, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-gods-promise-to-david', 'bible-tea', 's-2samuel', 'God''s Promise to David', 'gods-promise-to-david', 'David wants to build God a house. God flips it — ''I''ll build YOUR house. Your throne will last forever.''', 'stories/gods-promise-to-david/cover.webp', 151, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-kindness-to-mephibosheth', 'bible-tea', 's-2samuel', 'Kindness to Mephibosheth', 'kindness-to-mephibosheth', 'At the peak of his power, David hunts down Saul''s disabled grandson — not to kill him, but to invite him to dinner forever.', 'stories/kindness-to-mephibosheth/cover.webp', 152, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-absaloms-rise', 'bible-tea', 's-2samuel', 'Absalom''s Rise', 'absaloms-rise', 'David''s family fractures. Rape, revenge, exile — the consequences of Bathsheba ripple through his own house.', 'stories/absaloms-rise/cover.webp', 153, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-absaloms-rebellion', 'bible-tea', 's-2samuel', 'Absalom''s Rebellion', 'absaloms-rebellion', 'David''s own son steals the hearts of the people and forces the king to flee his own capital. Charisma without character.', 'stories/absaloms-rebellion/cover.webp', 154, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-a-fathers-worst-battle', 'bible-tea', 's-2samuel', 'A Father''s Worst Battle', 'a-fathers-worst-battle', 'David''s army fights Absalom''s. David wins the war but loses his son. ''O Absalom, my son, my son.'' Devastating.', 'stories/a-fathers-worst-battle/cover.webp', 155, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-davids-broken-return', 'bible-tea', 's-2samuel', 'David''s Broken Return', 'davids-broken-return', 'The king comes back to Jerusalem, but nothing is the same. Forgiveness is messy and repair takes longer than ruin.', 'stories/davids-broken-return/cover.webp', 156, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-davids-last-battles', 'bible-tea', 's-2samuel', 'David''s Last Battles', 'davids-last-battles', 'Giants fall, debts are settled, and psalms of thanks close out an era of warfare.', 'stories/davids-last-battles/cover.webp', 157, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-davids-final-mistake', 'bible-tea', 's-2samuel', 'David''s Final Mistake', 'davids-final-mistake', 'David orders a census out of pride. A plague follows. He buys a threshing floor that becomes the future temple site.', 'stories/davids-final-mistake/cover.webp', 158, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-elijah-on-mount-carmel', 'bible-tea', 's-1kings', 'Elijah on Mount Carmel', 'elijah-on-mount-carmel', 'One prophet vs 450 prophets of Baal. Build altars, call for fire. Only one God answers. Elijah doesn''t flinch.', 'stories/elijah-on-mount-carmel/cover.webp', 159, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-kingdom-splits', 'bible-tea', 's-1kings', 'The Kingdom Splits', 'the-kingdom-splits', 'Solomon''s son ignores wise advice and doubles down on harsh rule. One nation becomes two over one dumb decision.', 'stories/the-kingdom-splits/cover.webp', 160, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-kings-who-copied-the-worst', 'bible-tea', 's-2kings', 'Kings Who Copied the Worst', 'kings-who-copied-the-worst', 'One bad king after another copies the sins of those before. Cosmetic religion can''t cure deep rot.', 'stories/kings-who-copied-the-worst/cover.webp', 161, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-decay-coups-and-leprosy', 'bible-tea', 's-2kings', 'Decay, Coups & Leprosy', 'decay-coups-and-leprosy', 'Internal corruption invites external disaster. The monarchy slowly rots from the inside out.', 'stories/decay-coups-and-leprosy/cover.webp', 162, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-manasseh-hits-reverse', 'bible-tea', 's-2kings', 'Manasseh Hits Reverse', 'manasseh-hits-reverse', 'A son undoes his father''s reforms and drags the nation to its worst spiritual low. One generation can undo decades of progress.', 'stories/manasseh-hits-reverse/cover.webp', 163, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-josiah-finds-the-lost-book', 'bible-tea', 's-2kings', 'Josiah Finds the Lost Book', 'josiah-finds-the-lost-book', 'Workers find the Book of the Law buried in temple rubble. When the king hears it read, he tears his clothes and reforms everything.', 'stories/josiah-finds-the-lost-book/cover.webp', 164, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-josiahs-last-battle', 'bible-tea', 's-2chronicles', 'Josiah''s Last Battle', 'josiahs-last-battle', 'The revival king wages one final war. Altars are smashed, hearts are called home, but the clock is ticking on Judah.', 'stories/josiahs-last-battle/cover.webp', 165, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hezekiahs-extra-years', 'bible-tea', 's-2kings', 'Hezekiah''s Extra Years', 'hezekiahs-extra-years', 'God gives Hezekiah 15 more years, then he blows it by showing off his treasures to the wrong people.', 'stories/hezekiahs-extra-years/cover.webp', 166, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-one-angel-one-army-destroyed', 'bible-tea', 's-2kings', 'One Angel, One Army Destroyed', 'one-angel-one-army-destroyed', '185,000 Assyrian soldiers surround Jerusalem. Hezekiah prays. One angel. One night. The entire army is gone by morning.', 'stories/one-angel-one-army-destroyed/cover.webp', 167, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hezekiah-vs-the-empire', 'bible-tea', 's-2chronicles', 'Hezekiah vs. the Empire', 'hezekiah-vs-the-empire', 'A faithful king stares down the Assyrian war machine. Intimidation letters arrive. He spreads them before God and prays.', 'stories/hezekiah-vs-the-empire/cover.webp', 168, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-northern-kingdom-falls', 'bible-tea', 's-2kings', 'The Northern Kingdom Falls', 'the-northern-kingdom-falls', 'Centuries of bad kings catch up. Assyria conquers Israel and scatters the 10 tribes. They never come back.', 'stories/the-northern-kingdom-falls/cover.webp', 169, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-jerusalem-burns', 'bible-tea', 's-2kings', 'Jerusalem Burns', 'jerusalem-burns', 'Babylon breaks through the walls and burns the temple to the ground. The people are dragged into exile. Everything is gone.', 'stories/jerusalem-burns/cover.webp', 170, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-angel-visits-zechariah', 'bible-tea', 's-luke', 'An Angel Visits Zechariah', 'angel-visits-zechariah', 'An old priest gets an angel visit promising a miracle baby. He doubts it and loses his voice for 9 months.', 'stories/angel-visits-zechariah/cover.webp', 171, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-angel-visits-mary', 'bible-tea', 's-luke', 'An Angel Visits Mary', 'angel-visits-mary', 'A teenage girl gets told she''ll carry God''s son. She says yes. Joseph almost walks away. The most important pregnancy in history.', 'stories/angel-visits-mary/cover.webp', 172, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-birth-of-john-the-baptist', 'bible-tea', 's-luke', 'The Birth of John the Baptist', 'birth-of-john-the-baptist', 'The miracle baby arrives. Zechariah gets his voice back and prophesies. The forerunner of Jesus is born.', 'stories/birth-of-john-the-baptist/cover.webp', 173, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-simeon-and-anna', 'bible-tea', 's-luke', 'Simeon & Anna at the Temple', 'simeon-and-anna', 'Two elderly believers waited their whole lives to see the Messiah. They recognize a baby in his parents'' arms.', 'stories/simeon-and-anna/cover.webp', 174, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-wise-men', 'bible-tea', 's-matthew', 'The Wise Men', 'the-wise-men', 'Star-following scholars from the east bring gold, frankincense, and myrrh. King Herod is not happy about the competition.', 'stories/the-wise-men/cover.webp', 175, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-flight-to-egypt', 'bible-tea', 's-matthew', 'Flight to Egypt', 'flight-to-egypt', 'An angel warns Joseph in a dream. The family flees to Egypt in the night. Herod slaughters every baby boy in Bethlehem.', 'stories/flight-to-egypt/cover.webp', 176, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-boy-jesus-at-the-temple', 'bible-tea', 's-luke', 'Boy Jesus at the Temple', 'boy-jesus-at-the-temple', 'Twelve-year-old Jesus stays behind in the temple, debating scholars. His parents panic. He says ''I''m in my Father''s house.''', 'stories/boy-jesus-at-the-temple/cover.webp', 177, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-john-the-baptist-preaches', 'bible-tea', 's-matthew', 'John the Baptist Preaches', 'john-the-baptist-preaches', 'A wild man in the desert wearing camel hair, eating locusts, screaming ''repent.'' He''s preparing the way for someone bigger.', 'stories/john-the-baptist-preaches/cover.webp', 178, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-john-declares-the-lamb', 'bible-tea', 's-john', 'John Declares ''The Lamb of God''', 'john-declares-the-lamb', 'John sees Jesus coming and says ''Look — the Lamb of God.'' A prophet points past himself to the one who matters.', 'stories/john-declares-the-lamb/cover.webp', 179, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-40-days-in-the-desert', 'bible-tea', 's-matthew', '40 Days in the Desert', '40-days-in-the-desert', 'Starving and alone, Jesus faces the devil''s three best tricks. He shuts them all down with Scripture.', 'stories/40-days-in-the-desert/cover.webp', 180, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-meeting-the-first-disciples', 'bible-tea', 's-john', 'Meeting the First Disciples', 'meeting-the-first-disciples', 'Simple invitations — ''come and see'' — change the course of history. Fishermen drop their nets and follow.', 'stories/meeting-the-first-disciples/cover.webp', 181, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-nicodemus-comes-at-night', 'bible-tea', 's-john', 'Nicodemus Comes at Night', 'nicodemus-comes-at-night', 'A religious leader sneaks to Jesus after dark. ''You must be born again.'' The conversation that explains everything.', 'stories/nicodemus-comes-at-night/cover.webp', 182, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-jesus-flips-tables', 'bible-tea', 's-john', 'Jesus Flips Tables in the Temple', 'jesus-flips-tables', 'Jesus walks into the temple, sees it turned into a marketplace, and starts flipping tables. Nobody stops him.', 'stories/jesus-flips-tables/cover.webp', 183, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-john-the-baptists-last-words', 'bible-tea', 's-john', 'John the Baptist''s Last Words', 'john-the-baptists-last-words', 'As his own following shrinks, John says ''He must increase, I must decrease.'' A prophet who knew his role.', 'stories/john-the-baptists-last-words/cover.webp', 184, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-healing-at-the-pool', 'bible-tea', 's-john', 'Healing at the Pool of Bethesda', 'healing-at-the-pool', 'A man waits 38 years by a pool hoping for healing. Jesus walks up and says ''do you want to get well?'' One word and it''s done.', 'stories/healing-at-the-pool/cover.webp', 185, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-miraculous-catch', 'bible-tea', 's-luke', 'The Miraculous Catch of Fish', 'the-miraculous-catch', 'Professional fishermen catch nothing all night. Jesus says try again. The nets nearly break from the haul.', 'stories/the-miraculous-catch/cover.webp', 186, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-casting-out-an-evil-spirit', 'bible-tea', 's-mark', 'Casting Out an Evil Spirit', 'casting-out-an-evil-spirit', 'In the synagogue, a demon screams at Jesus. One command and it''s gone. The crowd is stunned — who IS this guy?', 'stories/casting-out-an-evil-spirit/cover.webp', 187, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-peters-mother-in-law-healed', 'bible-tea', 's-mark', 'Peter''s Mother-in-Law Healed', 'peters-mother-in-law-healed', 'Jesus touches her hand, the fever leaves, and she immediately gets up and starts serving dinner. Word spreads fast.', 'stories/peters-mother-in-law-healed/cover.webp', 188, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-touching-the-leper', 'bible-tea', 's-mark', 'Touching the Leper', 'touching-the-leper', 'Nobody touches lepers. Jesus reaches out his hand. ''I am willing. Be clean.'' The outcast is restored.', 'stories/touching-the-leper/cover.webp', 189, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-through-the-roof', 'bible-tea', 's-mark', 'Through the Roof', 'through-the-roof', 'Four friends can''t get through the crowd, so they rip open the roof and lower their paralyzed friend to Jesus. That''s friendship.', 'stories/through-the-roof/cover.webp', 190, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-matthew-leaves-everything', 'bible-tea', 's-matthew', 'Matthew Leaves Everything', 'matthew-leaves-everything', 'A hated tax collector hears ''follow me,'' walks away from the money table, and throws Jesus a dinner party with all his shady friends.', 'stories/matthew-leaves-everything/cover.webp', 191, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-sabbath-showdowns', 'bible-tea', 's-matthew', 'The Sabbath Showdowns', 'the-sabbath-showdowns', 'Jesus heals on the Sabbath and the religious leaders lose their minds. Rules were made for people, not the other way around.', 'stories/the-sabbath-showdowns/cover.webp', 192, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-picking-the-twelve', 'bible-tea', 's-luke', 'Picking the Twelve', 'picking-the-twelve', 'After a night of prayer, Jesus picks his squad — fishermen, a tax collector, a zealot, and a traitor. Interesting choices.', 'stories/picking-the-twelve/cover.webp', 193, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-centurions-faith', 'bible-tea', 's-matthew', 'The Centurion''s Faith', 'the-centurions-faith', 'A Roman soldier says ''just say the word and my servant will be healed.'' Jesus is blown away — this outsider has more faith than Israel.', 'stories/the-centurions-faith/cover.webp', 194, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-widows-son-lives-again', 'bible-tea', 's-luke', 'The Widow''s Son Lives Again', 'the-widows-son-lives-again', 'A funeral procession. A grieving mother. Jesus touches the coffin, says ''get up,'' and the dead man sits up. The crowd freaks out.', 'stories/the-widows-son-lives-again/cover.webp', 195, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-deaf-ears-opened', 'bible-tea', 's-mark', 'Deaf Ears Opened', 'deaf-ears-opened', 'A deaf man with a speech impediment meets Jesus. Ears open, tongue loosens, and the crowd can''t stop talking about it.', 'stories/deaf-ears-opened/cover.webp', 196, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-jesus-stops-a-storm', 'bible-tea', 's-mark', 'Jesus Stops a Storm', 'jesus-stops-a-storm', 'Waves crashing, boat sinking, disciples screaming. Jesus wakes up from a nap and tells the storm to shut up. It does.', 'stories/jesus-stops-a-storm/cover.webp', 197, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-legion-and-the-pigs', 'bible-tea', 's-mark', 'Legion & the Pigs', 'legion-and-the-pigs', 'A man possessed by thousands of demons lives in a graveyard. Jesus frees him in one sentence. The demons go into pigs.', 'stories/legion-and-the-pigs/cover.webp', 198, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-jairus-daughter-and-the-bleeding-woman', 'bible-tea', 's-mark', 'Jairus''s Daughter & the Bleeding Woman', 'jairus-daughter-and-the-bleeding-woman', 'One desperate father and one daring woman. Both need a miracle. Both get one. Faith interrupts death.', 'stories/jairus-daughter-and-the-bleeding-woman/cover.webp', 199, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-healing-the-officials-son', 'bible-tea', 's-john', 'Healing the Official''s Son', 'healing-the-officials-son', 'A royal official begs Jesus to heal his dying kid. Jesus says ''go home, your son is fine.'' He is.', 'stories/healing-the-officials-son/cover.webp', 200, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-demons-and-accusations', 'bible-tea', 's-matthew', 'Demons & Accusations', 'demons-and-accusations', 'Jesus casts out a demon and the Pharisees accuse him of working for Satan. Jesus dismantles their logic in seconds.', 'stories/demons-and-accusations/cover.webp', 201, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-john-the-baptist-beheaded', 'bible-tea', 's-matthew', 'John the Baptist Beheaded', 'john-the-baptist-beheaded', 'A birthday party, a dance, and a horrifying request. The greatest prophet loses his head because of a grudge.', 'stories/john-the-baptist-beheaded/cover.webp', 202, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-feeding-4000', 'bible-tea', 's-matthew', 'Jesus Feeds 4,000', 'feeding-4000', 'Different crowd, same compassion. A few loaves, a few fish, thousands fed. Bread becomes a recurring theme.', 'stories/feeding-4000/cover.webp', 203, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-bread-of-life', 'bible-tea', 's-john', 'Bread of Life', 'bread-of-life', 'After the miracle meal, Jesus says ''I AM the bread of life.'' The crowd wanted food. He offered himself. Many walk away.', 'stories/bread-of-life/cover.webp', 204, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-purity-debate', 'bible-tea', 's-mark', 'The Purity Debate', 'the-purity-debate', 'The Pharisees obsess over hand-washing rituals. Jesus says it''s not what goes into you that defiles — it''s what comes out of your heart.', 'stories/the-purity-debate/cover.webp', 205, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-a-mothers-desperate-faith', 'bible-tea', 's-mark', 'A Mother''s Desperate Faith', 'a-mothers-desperate-faith', 'A Syrophoenician woman begs Jesus to heal her daughter. He tests her. She fires back with one of the best comebacks in the Bible.', 'stories/a-mothers-desperate-faith/cover.webp', 206, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-peters-big-confession', 'bible-tea', 's-matthew', 'Peter''s Big Confession', 'peters-big-confession', '''Who do you say I am?'' Peter nails it — ''You''re the Christ.'' Then Jesus drops the first prediction of his death.', 'stories/peters-big-confession/cover.webp', 207, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-transfiguration', 'bible-tea', 's-matthew', 'The Transfiguration', 'the-transfiguration', 'Jesus takes three disciples up a mountain. His face blazes like the sun. Moses and Elijah appear. Peter wants to build tents.', 'stories/the-transfiguration/cover.webp', 208, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-boy-with-a-demon', 'bible-tea', 's-matthew', 'The Boy with a Demon', 'the-boy-with-a-demon', 'The disciples can''t heal a demon-possessed boy. Jesus does it instantly and says ''this kind requires prayer and fasting.''', 'stories/the-boy-with-a-demon/cover.webp', 209, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-jesus-predicts-his-death', 'bible-tea', 's-matthew', 'Jesus Predicts His Death', 'jesus-predicts-his-death', 'Jesus tells the disciples exactly what''s coming — betrayal, death, resurrection. They don''t understand. He says it three times.', 'stories/jesus-predicts-his-death/cover.webp', 210, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-fish-with-a-coin', 'bible-tea', 's-matthew', 'The Fish with a Coin', 'the-fish-with-a-coin', 'Tax collectors come asking. Jesus tells Peter to catch a fish — there''ll be a coin in its mouth. There is. Bill paid.', 'stories/the-fish-with-a-coin/cover.webp', 211, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-festival-showdown', 'bible-tea', 's-john', 'The Festival Showdown', 'the-festival-showdown', 'Jesus shows up at the Feast of Tabernacles and the crowds are split — prophet, deceiver, or Messiah? Tension is thick.', 'stories/the-festival-showdown/cover.webp', 212, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-born-blind-now-sees', 'bible-tea', 's-john', 'Born Blind, Now Sees', 'born-blind-now-sees', 'Jesus heals a man blind from birth. The Pharisees interrogate him relentlessly. His answer is simple: ''I was blind. Now I see.''', 'stories/born-blind-now-sees/cover.webp', 213, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-good-shepherd', 'bible-tea', 's-john', 'The Good Shepherd', 'the-good-shepherd', '''I am the good shepherd. The good shepherd lays down his life for the sheep.'' Jesus defines leadership by sacrifice.', 'stories/the-good-shepherd/cover.webp', 214, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-sending-out-72', 'bible-tea', 's-luke', 'Sending Out 72 Missionaries', 'sending-out-72', 'Jesus sends 72 followers ahead of him in pairs. They come back amazed — even demons obey them.', 'stories/sending-out-72/cover.webp', 215, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-mary-and-martha', 'bible-tea', 's-luke', 'Mary & Martha', 'mary-and-martha', 'One sister is hustling in the kitchen, the other is sitting at Jesus'' feet. Martha complains. Jesus sides with Mary.', 'stories/mary-and-martha/cover.webp', 216, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-teaching-them-to-pray', 'bible-tea', 's-luke', 'Teaching Them to Pray', 'teaching-them-to-pray', '''Lord, teach us to pray.'' Jesus gives them the simplest, most powerful prayer in history. Then tells a story about persistence.', 'stories/teaching-them-to-pray/cover.webp', 217, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-casting-out-demons-and-taking-heat', 'bible-tea', 's-luke', 'Casting Out Demons & Taking Heat', 'casting-out-demons-and-taking-heat', 'Jesus drives out a demon. Some say he''s using Satan''s power. Jesus dismantles the accusation and warns about empty houses.', 'stories/casting-out-demons-and-taking-heat/cover.webp', 218, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-calling-out-the-pharisees', 'bible-tea', 's-luke', 'Calling Out the Pharisees', 'calling-out-the-pharisees', 'Jesus accepts a dinner invite then absolutely roasts the Pharisees to their faces. Hypocrisy gets exposed at the table.', 'stories/calling-out-the-pharisees/cover.webp', 219, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-woman-at-the-well', 'bible-tea', 's-john', 'The Woman at the Well', 'the-woman-at-the-well', 'A Samaritan outcast meets Jesus at a well. He knows everything about her. She becomes the first evangelist.', 'stories/the-woman-at-the-well/cover.webp', 220, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-lazarus-lives-again', 'bible-tea', 's-john', 'Lazarus Lives Again', 'lazarus-lives-again', 'Dead four days, sealed in a tomb. Jesus weeps, then shouts ''Lazarus, come out!'' And he does. The ultimate mic drop.', 'stories/lazarus-lives-again/cover.webp', 221, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-go-ahead-throw-a-stone', 'bible-tea', 's-john', 'Go Ahead, Throw a Stone', 'go-ahead-throw-a-stone', 'A woman caught in adultery is dragged before Jesus. ''Let the one without sin throw first.'' One by one, they walk away.', 'stories/go-ahead-throw-a-stone/cover.webp', 222, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-wedding-feast-parables', 'bible-tea', 's-luke', 'The Wedding Feast Parables', 'the-wedding-feast-parables', 'Invitations go out to the VIPs. They all make excuses. So the host invites everyone from the streets instead.', 'stories/the-wedding-feast-parables/cover.webp', 223, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-narrow-door', 'bible-tea', 's-luke', 'The Narrow Door', 'the-narrow-door', '''Strive to enter through the narrow door.'' Many will try and fail. Urgency rings out — don''t wait.', 'stories/the-narrow-door/cover.webp', 224, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-counting-the-cost', 'bible-tea', 's-luke', 'Counting the Cost', 'counting-the-cost', 'Following Jesus isn''t casual. Count the cost first. He''s not looking for fans — he wants people who''ll carry a cross.', 'stories/counting-the-cost/cover.webp', 225, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-shrewd-manager', 'bible-tea', 's-luke', 'The Shrewd Manager', 'the-shrewd-manager', 'A manager about to get fired cuts deals with his boss''s debtors. Jesus praises the hustle. Wait, what?', 'stories/the-shrewd-manager/cover.webp', 226, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-rich-man-and-lazarus', 'bible-tea', 's-luke', 'The Rich Man & Lazarus', 'the-rich-man-and-lazarus', 'A rich man ignores a beggar at his gate. They both die. The reversal on the other side is permanent.', 'stories/the-rich-man-and-lazarus/cover.webp', 227, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-zacchaeus-climbs-a-tree', 'bible-tea', 's-luke', 'Zacchaeus Climbs a Tree', 'zacchaeus-climbs-a-tree', 'A short, rich tax collector climbs a sycamore to see Jesus. Jesus spots him and invites himself to dinner. Everything changes.', 'stories/zacchaeus-climbs-a-tree/cover.webp', 228, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-cursed-fig-tree', 'bible-tea', 's-mark', 'The Cursed Fig Tree & Temple Fury', 'the-cursed-fig-tree', 'Jesus curses a fruitless fig tree and clears the temple of merchants. Both acts say the same thing: bear fruit or be cut off.', 'stories/the-cursed-fig-tree/cover.webp', 229, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-palm-sunday', 'bible-tea', 's-matthew', 'Palm Sunday', 'palm-sunday', 'Jesus rides into Jerusalem on a donkey. Crowds wave palms and shout ''Hosanna!'' The king arrives — but not how anyone expected.', 'stories/palm-sunday/cover.webp', 230, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-caesars-coin', 'bible-tea', 's-matthew', 'Caesar''s Coin', 'caesars-coin', 'They try to trap Jesus with a political question. He asks for a coin. ''Give to Caesar what''s Caesar''s, and to God what''s God''s.'' Mic drop.', 'stories/caesars-coin/cover.webp', 231, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-faith-figs-and-loaded-questions', 'bible-tea', 's-matthew', 'Faith, Figs & Loaded Questions', 'faith-figs-and-loaded-questions', 'Religious leaders fire trap after trap at Jesus. He answers every one and fires back harder.', 'stories/faith-figs-and-loaded-questions/cover.webp', 232, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-marriage-and-the-afterlife', 'bible-tea', 's-matthew', 'Marriage & the Afterlife', 'marriage-and-the-afterlife', 'The Sadducees think they''ve got Jesus with a brain teaser about marriage after death. He shuts it down in one sentence.', 'stories/marriage-and-the-afterlife/cover.webp', 233, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-greatest-commandment', 'bible-tea', 's-matthew', 'The Greatest Commandment', 'the-greatest-commandment', '''Love God with everything. Love your neighbor as yourself.'' The entire law and prophets hang on these two lines.', 'stories/the-greatest-commandment/cover.webp', 234, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-whose-son-is-the-messiah', 'bible-tea', 's-matthew', 'Whose Son Is the Messiah?', 'whose-son-is-the-messiah', 'Jesus asks the Pharisees a riddle about David''s son. Nobody can answer. He reveals the Messiah is bigger than they imagined.', 'stories/whose-son-is-the-messiah/cover.webp', 235, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-signs-of-the-end', 'bible-tea', 's-matthew', 'Signs of the End', 'signs-of-the-end', 'On the Mount of Olives, Jesus describes the end of the world — wars, earthquakes, deception. ''Stay ready. You don''t know the day.''', 'stories/signs-of-the-end/cover.webp', 236, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-plot-against-jesus', 'bible-tea', 's-matthew', 'The Plot Against Jesus', 'the-plot-against-jesus', 'The religious leaders have had enough. They start scheming in secret to arrest and kill Jesus before the festival ends.', 'stories/the-plot-against-jesus/cover.webp', 237, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-judas-makes-a-deal', 'bible-tea', 's-matthew', 'Judas Makes a Deal', 'judas-makes-a-deal', 'Thirty silver coins. That''s the price Judas puts on Jesus. He walks to the priests and offers to hand him over.', 'stories/judas-makes-a-deal/cover.webp', 238, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-anointed-at-bethany', 'bible-tea', 's-john', 'Anointed at Bethany', 'anointed-at-bethany', 'A woman pours expensive perfume on Jesus. The disciples say it''s wasteful. Jesus says she''s preparing him for burial.', 'stories/anointed-at-bethany/cover.webp', 239, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-gethsemane', 'bible-tea', 's-matthew', 'Gethsemane', 'gethsemane', '''Take this cup from me. But not my will — yours.'' In crushing sorrow, Jesus chooses obedience over escape.', 'stories/gethsemane/cover.webp', 240, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-arrested-in-the-garden', 'bible-tea', 's-matthew', 'Arrested in the Garden', 'arrested-in-the-garden', 'A kiss from Judas. Torches and swords. Peter swings a sword and cuts off an ear. Jesus heals it and surrenders.', 'stories/arrested-in-the-garden/cover.webp', 241, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-before-the-sanhedrin', 'bible-tea', 's-matthew', 'Before the Sanhedrin', 'before-the-sanhedrin', 'False witnesses, loaded questions, and one honest answer: ''I am.'' The high priest tears his robes. Guilty of blasphemy.', 'stories/before-the-sanhedrin/cover.webp', 242, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-peters-three-denials', 'bible-tea', 's-matthew', 'Peter''s Three Denials', 'peters-three-denials', '''I don''t know him.'' Three times. Then the rooster crows. Peter remembers and breaks down crying.', 'stories/peters-three-denials/cover.webp', 243, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-jesus-before-pilate', 'bible-tea', 's-matthew', 'Jesus Before Pilate', 'jesus-before-pilate', 'Pilate finds no fault in him. The crowd screams for crucifixion. He washes his hands and hands Jesus over.', 'stories/jesus-before-pilate/cover.webp', 244, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-buried-in-a-borrowed-tomb', 'bible-tea', 's-matthew', 'Buried in a Borrowed Tomb', 'buried-in-a-borrowed-tomb', 'Joseph of Arimathea takes the body down, wraps it in linen, and places it in his own new tomb. A stone seals the entrance.', 'stories/buried-in-a-borrowed-tomb/cover.webp', 245, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-road-to-emmaus', 'bible-tea', 's-luke', 'The Road to Emmaus', 'the-road-to-emmaus', 'Two heartbroken disciples walk home. A stranger joins them and explains the Scriptures. When he breaks bread, they realize — it''s Jesus.', 'stories/the-road-to-emmaus/cover.webp', 246, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-doubting-thomas', 'bible-tea', 's-john', 'Doubting Thomas', 'doubting-thomas', '''Unless I put my finger in the nail holes, I won''t believe.'' Jesus shows up and says ''go ahead.'' Thomas falls to his knees.', 'stories/doubting-thomas/cover.webp', 247, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-great-commission', 'bible-tea', 's-matthew', 'The Great Commission', 'the-great-commission', '''Go and make disciples of all nations.'' Jesus gives the final mission statement before leaving earth.', 'stories/the-great-commission/cover.webp', 248, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-ascension', 'bible-tea', 's-acts', 'The Ascension', 'the-ascension', 'Jesus leads his disciples to a hillside, blesses them, and rises into the sky. Two angels say ''he''ll be back.''', 'stories/the-ascension/cover.webp', 249, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-pentecost', 'bible-tea', 's-acts', 'Pentecost', 'pentecost', 'The Holy Spirit arrives like fire and wind. Everyone starts speaking languages they never learned. The church is born.', 'stories/pentecost/cover.webp', 250, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-beautiful-gate-miracle', 'bible-tea', 's-acts', 'The Beautiful Gate Miracle', 'the-beautiful-gate-miracle', 'A disabled beggar asks Peter for money. Peter says ''I don''t have money, but I have something better.'' The man walks.', 'stories/the-beautiful-gate-miracle/cover.webp', 251, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-ananias-and-sapphira', 'bible-tea', 's-acts', 'Ananias & Sapphira', 'ananias-and-sapphira', 'A couple lies about their donation to the church. They both drop dead. God is not messing around with fakes in the early church.', 'stories/ananias-and-sapphira/cover.webp', 252, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-stephen-the-first-martyr', 'bible-tea', 's-acts', 'Stephen, the First Martyr', 'stephen-the-first-martyr', 'A man full of faith and fire preaches the truth. They stone him to death. He forgives them while dying.', 'stories/stephen-the-first-martyr/cover.webp', 253, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-church-scatters', 'bible-tea', 's-acts', 'The Church Scatters & Philip', 'the-church-scatters', 'Persecution scatters believers everywhere. Philip ends up baptizing an Ethiopian official on a desert road. The gospel spreads.', 'stories/the-church-scatters/cover.webp', 254, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-saul-meets-jesus', 'bible-tea', 's-acts', 'Saul Meets Jesus on the Road', 'saul-meets-jesus', 'A Christian-hunter gets blinded by a light. Jesus says ''why are you persecuting me?'' Saul becomes Paul. The greatest 180 in history.', 'stories/saul-meets-jesus/cover.webp', 255, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-peters-miracles', 'bible-tea', 's-acts', 'Peter''s Miracles in Lydda & Joppa', 'peters-miracles', 'Peter heals a paralyzed man and raises a dead woman. The apostles are walking in the same power Jesus had.', 'stories/peters-miracles/cover.webp', 256, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cornelius-and-the-vision', 'bible-tea', 's-acts', 'Cornelius & the Sheet Vision', 'cornelius-and-the-vision', 'God sends Peter a vision of forbidden food and says ''eat.'' The message: salvation isn''t just for Jews anymore.', 'stories/cornelius-and-the-vision/cover.webp', 257, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-antioch-church', 'bible-tea', 's-acts', 'The Antioch Church', 'the-antioch-church', 'A diverse church launches in Antioch. For the first time, followers of Jesus are called ''Christians.''', 'stories/the-antioch-church/cover.webp', 258, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-james-killed-peter-escapes', 'bible-tea', 's-acts', 'James Killed, Peter Escapes', 'james-killed-peter-escapes', 'King Herod executes James. He arrests Peter too — but an angel breaks him out of prison in the middle of the night.', 'stories/james-killed-peter-escapes/cover.webp', 259, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-pauls-first-journey', 'bible-tea', 's-acts', 'Paul''s First Missionary Journey', 'pauls-first-journey', 'Paul and Barnabas hit the road. New churches spring up, old habits resist, and the gospel goes where it''s never been.', 'stories/pauls-first-journey/cover.webp', 260, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-jerusalem-council', 'bible-tea', 's-acts', 'The Jerusalem Council', 'the-jerusalem-council', 'The early church debates the biggest question: do non-Jews have to follow Jewish law? They land on grace.', 'stories/the-jerusalem-council/cover.webp', 261, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-earthquake-at-philippi', 'bible-tea', 's-acts', 'Earthquake at Philippi', 'earthquake-at-philippi', 'Paul and Silas are in prison, singing hymns at midnight. An earthquake blows the doors open. The jailer converts.', 'stories/earthquake-at-philippi/cover.webp', 262, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-thessalonica-riot-and-berea', 'bible-tea', 's-acts', 'Thessalonica Riot & Berean Scholars', 'thessalonica-riot-and-berea', 'One city riots, the next one fact-checks Scripture daily. Two very different receptions for the same message.', 'stories/thessalonica-riot-and-berea/cover.webp', 263, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-athens-the-unknown-god', 'bible-tea', 's-acts', 'Athens: The Unknown God', 'athens-the-unknown-god', 'Paul finds an altar labeled ''To an Unknown God.'' He says ''let me introduce him.'' Philosophy meets revelation.', 'stories/athens-the-unknown-god/cover.webp', 264, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-riot-in-ephesus', 'bible-tea', 's-acts', 'Riot in Ephesus & the Bonfire', 'riot-in-ephesus', 'Believers burn their magic books worth millions. Silversmiths riot because they''re losing money. Power confronts profit.', 'stories/riot-in-ephesus/cover.webp', 265, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-eutychus-falls-out-a-window', 'bible-tea', 's-acts', 'Eutychus Falls Out a Window', 'eutychus-falls-out-a-window', 'Paul preaches so long that a young man falls asleep, falls out a third-story window, and dies. Paul raises him back.', 'stories/eutychus-falls-out-a-window/cover.webp', 266, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-farewell-at-miletus', 'bible-tea', 's-acts', 'Farewell at Miletus', 'farewell-at-miletus', 'Paul says goodbye to the church leaders at Miletus. There are tears on the shore. He knows he won''t see them again.', 'stories/farewell-at-miletus/cover.webp', 267, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-arrested-at-the-temple', 'bible-tea', 's-acts', 'Arrested at the Temple', 'arrested-at-the-temple', 'Paul visits the temple in Jerusalem and a mob drags him out. Roman soldiers save his life. The trials begin.', 'stories/arrested-at-the-temple/cover.webp', 268, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-trials-before-governors', 'bible-tea', 's-acts', 'Trials Before Governors', 'trials-before-governors', 'Paul gets passed from one Roman official to another. Each one finds no fault, but nobody sets him free. He appeals to Caesar.', 'stories/trials-before-governors/cover.webp', 269, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-shipwreck-and-malta', 'bible-tea', 's-acts', 'Shipwreck & Malta', 'shipwreck-and-malta', 'A brutal storm, 14 days lost at sea, the ship breaks apart. Everyone makes it to shore. A snake bites Paul. He shakes it off.', 'stories/shipwreck-and-malta/cover.webp', 270, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-paul-under-house-arrest', 'bible-tea', 's-acts', 'Paul Under House Arrest', 'paul-under-house-arrest', 'Chained to a Roman guard in a rented room, Paul keeps preaching. Chains can''t stop the word.', 'stories/paul-under-house-arrest/cover.webp', 271, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-james-writes-to-the-church', 'bible-tea', 's-james', 'James Writes to the Church', 'james-writes-to-the-church', 'Practical wisdom for scattered believers. Faith without action is dead. Control your tongue. Help the poor. No excuses.', 'stories/james-writes-to-the-church/cover.webp', 272, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-peters-final-letter', 'bible-tea', 's-2peter', 'Peter''s Final Letter', 'peters-final-letter', 'An aging apostle warns about false teachers and reminds the church: he SAW Jesus transfigured on that mountain. This isn''t fiction.', 'stories/peters-final-letter/cover.webp', 273, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-pauls-last-letter', 'bible-tea', 's-2timothy', 'Paul''s Last Letter', 'pauls-last-letter', 'From a Roman prison, Paul writes to Timothy one final time. ''I have fought the good fight. I have finished the race.''', 'stories/pauls-last-letter/cover.webp', 274, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-johns-exile-and-revelation', 'bible-tea', 's-revelation', 'John''s Exile & Revelation', 'johns-exile-and-revelation', 'Exiled to an island, the last living apostle receives a vision of heaven, judgment, and the end of all things.', 'stories/johns-exile-and-revelation/cover.webp', 275, 0, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-new-heaven-and-new-earth', 'bible-tea', 's-revelation', 'The New Heaven & New Earth', 'the-new-heaven-and-new-earth', 'God wipes every tear. No more death, pain, or crying. Everything is made new. The story ends where it began — God with his people.', 'stories/the-new-heaven-and-new-earth/cover.webp', 276, 0, 1);

